function printHelp(): void {
  console.log(`
  Todo CLI

  Commands:
    list --data <path>        List all tasks
    add <title> --data <path>  Add a new task
    done <id> --data <path>    Mark task as done
    remove <id> --data <path>  Remove a task

  All commands require --data <path> to specify the JSON file.
  --help                       Show this help
`);
}

function main() {
  const argv = process.argv.slice(2);
  if (argv.length === 0) {
    printHelp();
    process.exit(0);
  }

  const helpFlag = argv.includes("--help");
  if (helpFlag) {
    printHelp();
    process.exit(0);
  }

  const dataIdx = argv.indexOf("--data");
  if (dataIdx === -1 || dataIdx + 1 >= argv.length) {
    console.error("Error: --data <path> is required");
    process.exit(1);
  }

  const dataPath = argv[dataIdx + 1];
  const cmd = argv[0];
  const args = argv.slice(1);

  if (cmd === "list") {
    const listArgs = args.filter(arg => arg !== "--data" && arg !== dataPath);
    if (listArgs.length > 0) {
      console.error("Error: Unexpected arguments for list");
      process.exit(1);
    }
    const tasks = listTasks(dataPath);
    console.log(JSON.stringify({ ok: true, tasks }));
  } else if (cmd === "add") {
    const title = args.find(arg => !arg.startsWith("--"));
    if (!title) {
      console.error("Error: Title is required for add");
      process.exit(1);
    }
    const addArgs = args.filter(arg => arg !== "--data" && arg !== dataPath);
    if (addArgs.length > 1) {
      console.error("Error: Unexpected arguments for add");
      process.exit(1);
    }
    const task = addTask(title, dataPath);
    console.log(JSON.stringify({ ok: true, task }));
  } else if (cmd === "done") {
    const id = args.find(arg => !arg.startsWith("--"));
    if (!id) {
      console.error("Error: ID is required for done");
      process.exit(1);
    }
    const doneArgs = args.filter(arg => arg !== "--data" && arg !== dataPath);
    if (doneArgs.length > 1) {
      console.error("Error: Unexpected arguments for done");
      process.exit(1);
    }
    const task = doneTask(id, dataPath);
    console.log(JSON.stringify({ ok: true, task }));
  } else if (cmd === "remove") {
    const id = args.find(arg => !arg.startsWith("--"));
    if (!id) {
      console.error("Error: ID is required for remove");
      process.exit(1);
    }
    const removeArgs = args.filter(arg => arg !== "--data" && arg !== dataPath);
    if (removeArgs.length > 1) {
      console.error("Error: Unexpected arguments for remove");
      process.exit(1);
    }
    const task = removeTask(id, dataPath);
    console.log(JSON.stringify({ ok: true, task }));
  } else {
    console.error(`Error: Unknown command "${cmd}"`);
    process.exit(1);
  }
}

function listTasks(dataPath: string): Task[] {
  const store = new (require("./store")).TaskStore(dataPath);
  return store.list();
}

function addTask(title: string, dataPath: string): Task {
  const store = new (require("./store")).TaskStore(dataPath);
  return store.add(title);
}

function doneTask(id: string, dataPath: string): Task {
  const store = new (require("./store")).TaskStore(dataPath);
  return store.done(id);
}

function removeTask(id: string, dataPath: string): Task {
  const store = new (require("./store")).TaskStore(dataPath);
  return store.remove(id);
}

function parseArgs(): string[] {
  return process.argv.slice(2);
}

main();

